var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"무척이나 혼란스러운 표정이시군요.","JPN":"とても混乱しているようですね。","ENG":"You look confused.","TWN":"你的表情相當困惑。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아합…….","JPN":"アハブ……","ENG":"Ahab...","TWN":"亞哈……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"우리는…… 관리국의…….","JPN":"私たちは……管理局の……","ENG":"We... The Administration...","TWN":"我們……管理局的……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh...!","TWN":"呃……！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"이런, 아직도 기억을 떠올리려 애쓰는 건가요?","JPN":"おっと、まだ記憶を思い出そうと頑張っているのですか？","ENG":"Oh, my. Are you still trying to recall your memories?","TWN":"哎呀，還在努力回憶嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"아쉽게도, 정보 말소된 기억은 쉽게 돌아오지 않습니다.","JPN":"残念ながら、情報が抹消された記憶はそう簡単には戻りません。","ENG":"Unfortunately, erased memories do not come back so easily.","TWN":"可惜的是，被抹除的記憶不會輕易恢復。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"다행스럽게도, 당신이 찾는 기억은 모두 우리가 가지고 있습니다.","JPN":"幸い、あなたが探している記憶はすべて私たちが持っています。","ENG":"Luckily, however, we have all the memories you are searching for.","TWN":"幸運的是，我們擁有你要找的所有記憶。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리와 함께하게 될 당신을 위해…… 아주 소중히 간직했죠.","JPN":"私たちと共になるであろうあなたのために……とても大事に保管していました。","ENG":"We have kept them safe for you... to join us.","TWN":"為了將要和我們一起的你……我一直珍藏著它。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리는 언제든 당신과 함께할 준비가 되어 있습니다.","JPN":"私たちはいつでもあなたと共になる準備ができています。","ENG":"We are ready to embrace you with open arms.","TWN":"我們隨時都準備好與你並肩作戰。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신이 깨어나기를 얼마나 학수고대했는지……!","JPN":"あなたが目覚めることをどれほど待ち望んでいたことか……！","ENG":"You don't know how long we've waited for you to wake up...!","TWN":"我有多麼地盼望你醒來……！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내가 동결되어 있었다는 걸 알았나?","JPN":"私が凍結されているということを知っていたのか？","ENG":"You knew I was in a cryogenic state?","TWN":"你知道我被冰封起來嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신의 기척이 사라진 것 정도는 파악하고 있었습니다.","JPN":"あなたの気配が消えたことくらいは把握済みでした。","ENG":"We were able to figure it out by detecting that your presence had disappeared.","TWN":"至少知道你的氣息消失了。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우리는 한때 짐승이었으나, 당신이 한 말을 떠올리며 정신을 되찾았습니다.","JPN":"私たちはかつて獣でしたが、あなたの言葉を思い出して正気を取り戻したのです。","ENG":"We were once beasts, but your words had brought us back to our senses.","TWN":"我們曾經是野獸，但你的話讓我們恢復理智。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"바로 당신의 말이었죠. <color=#ffd34c>모든 이름에는 힘이 담겨 있다. </color>","JPN":"それはこの言葉です。<color=#ffd34c>すべての名には力が宿っている。</color>","ENG":"Your exact words were, <color=#ffd34c>\\"All names contain power.\\"</color>","TWN":"<color=#ffd34c>所有的名字都蘊含著力量。</color>"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"<color=#ffd34c>우리는 세상의 어둠을 정화하기 위해 모인 자들이다. </color>라고.","JPN":"<color=#ffd34c>私たちは世界の闇を浄化するために集った者たちだ</color>、と。","ENG":"<color=#ffd34c>\\"We are those who have gathered to purify the world from darkness.\\"</color>","TWN":"<color=#ffd34c>我們是為淨化世界的黑暗而聚集在一起的人。</color>"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그래서 내가 깨어나자 모래 폭풍이…….","JPN":"それで私が目覚めると砂嵐が……","ENG":"So that's why there was a sandstorm when I woke up...","TWN":"所以當我醒來時才會有那場沙塵暴……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"허수 공간에서 현실로 이동하는 건 반동이 크거든요.","JPN":"虚数空間から現実に移動する時の反動は大きいですからね。","ENG":"Traversing from the imaginary space to the Normalside creates a strong recoil.","TWN":"從虛數空間移動到現世會有很大的反作用力。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이젠 침식체라는 사실을 숨기지도 않는 건가?","JPN":"もはや侵食体という事実を隠す気もないのか？","ENG":"Are you no longer hiding the fact that you're a C.O. now?","TWN":"現在也不隱藏自己是侵蝕體的事實了嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"숨기지 않은 게 아닙니다. 더 이상 당신을 혼자두지 않기 위해서 선택한 방법일 뿐이죠.","JPN":"隠していないわけではありません。もうあなたを一人にしないために選んだ方法であるだけです。","ENG":"It's not that I didn't hide it. It is merely a choice I made to not leave you alone anymore.","TWN":"我並不是想隱藏什麼。這只是我選擇的一種方式，為了不再讓你一個人孤單。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"제가 당신 옆에 있던 그 불순물을 삼킨 것도 그런 이유에서였습니다.","JPN":"私があなたの隣にいたあの不純物を飲み込んだのも、その理由からでした。","ENG":"It is also the reason why I swallowed the impurity that was beside you.","TWN":"我也是為此，才吞下你身邊的那個雜質。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"내 옆에 있던 불순물……?","JPN":"私の隣にいた不純物……？","ENG":"The impurity beside me?","TWN":"在我旁邊的雜質……？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아샤!","JPN":"アーシャ！","ENG":"Asha!","TWN":"阿莎！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"자격도 없는 년이 감히 우리의 태양 옆에 있다니요. 가당치도 않은 소리죠.","JPN":"資格もないクソ女が私たちの太陽のそばにいるなど。とんでもありません。","ENG":"How dare this unworthy girl stand beside our sun? The absurdity!","TWN":"一個沒有資格的女人怎麼敢站在我們的太陽身旁？荒謬！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"하지만, 그 불순물에게 당신과 관련된 물건이 하나 있지 뭡니까.","JPN":"ですが、あの不純物があなたと関係のある物を一つ持っていたのです。","ENG":"However, that impurity has one item related to you.","TWN":"只不過，那個雜質手裡有一件和你有關的東西……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그자도 우릴 받아들이고 이 자리에 있었다면 일이 더 수월했을텐데…….","JPN":"あの者も私たちを受け入れてこの場にいたのなら、もっと楽だったのですが……","ENG":"This would have been a lot easier if she was here and also accepted us.","TWN":"要世她也接受我們並站在這裡的話，事情本會更加順利……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"닥쳐라. 침식체. 아샤가 아직 살아있다는 말인가?","JPN":"黙れ、侵食体。アーシャはまだ生きているということか？","ENG":"Shut up, C.O. Is Asha still alive?","TWN":"閉嘴，侵蝕體。你是說阿莎還活著嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그 불순물은……영원히 행복해질 수 있는 선택을 거부했습니다.","JPN":"あの不純物は……永遠に幸せになれる選択を拒否しました。","ENG":"That impurity has... refused to be eternally happy.","TWN":"那個雜質……拒絕能夠永遠幸福的選擇。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"얌전히 우리에게 나침반을 넘겼다면 아무것도 잃지 않고, 부족하지 않은 세상에서 살 수 있었을 텐데.","JPN":"大人しく私たちに羅針盤を渡していれな何も失うことなく、すべてにおいて恵まれた世界で暮らせたはずなのに。","ENG":"If she had given us the compass, she would have lost nothing and lived in a bountiful world.","TWN":"如果她能乖乖地把指南針交給我們，就能活在一個應有盡有的世界裡，不會再失去任何東西。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"우연이었지만 그 불순물 역시 당신의 은총이라고 생각하고 있습니다.","JPN":"想定外でしたが、あの不純物もまたあなたの恵みであると思っています。","ENG":"It may be a coincidence, but that impurity seems to have your grace.","TWN":"雖然是偶然，但我認為那個雜質也是你的恩惠。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신이 우리에게 준 <color=#ff3636>라비의 이름을 가질 자격</color>을 위한 시험.","JPN":"あなたが私たちにくれた<color=#ff3636>ラビの名を持つ資格</color>を確認するための試練。","ENG":"A test you gave us to see <color=#ff3636>if we are worthy of the name Ravi</color>.","TWN":"你給我們的那場<color=#ff3636>是否擁有拉維之名資格</color>的試煉……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"반드시 당신의 기대에 부응하도록 하겠습니다. ","JPN":"必ずあなたの期待に応えられるように頑張ります。 ","ENG":"We will make sure to not let you down.","TWN":"我們一定會滿足你的期待。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"아, 그렇다고 해서 육신을 훼손할 생각은 없습니다.","JPN":"あっ、だからといって肉体を傷つけるつもりはありません。","ENG":"Oh, but that doesn't mean that we have any intention of harming her body.","TWN":"不過，我並沒有打算毀壞她的身體。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그 불순물의 육신은 원형 그대로 보존해서…….","JPN":"あの不純物の肉体は原型をそのまま保存して……","ENG":"We will preserve the impurity's body in its original form–","TWN":"我們會原樣保存她的肉體……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"이런. 그새 불순물에게 정을 많이 붙이셨나 봅니다?","JPN":"おっと。あの短い間に、あの不純物と親密になられたようですね。","ENG":"Oh. Have you gotten attached to that impurity?","TWN":"可惡，莫非你已經對那個雜質產生感情？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"역시 침식체답게 대화가 안 통하길래, 확실한 대화 방법을 택한 거다.","JPN":"侵食体らしく言葉が通じないから確実な会話手段を選択しただけだ。","ENG":"As expected, there is no use talking to C.O.s, so I chose a better means of communication.","TWN":"果然是無法溝通的侵蝕體，既然如此，我選擇更直接的交流方式。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"정…… 그래. 정을 많이 붙였지. 아샤가 질리는 타입은 아니었거든.","JPN":"親密……ああ、そうだ。アーシャは人をうんざりとさせるタイプではなかったからな。","ENG":"Attached... yes. She did grow on me. Asha's not really someone you get tired of.","TWN":"感情……沒錯。阿莎不是那種讓人厭煩的類型。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"역시 강한 아이야.","JPN":"さすが強い子だ。","ENG":"She's a strong kid.","TWN":"她是個堅強的孩子。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"도망…… 치세요. 아디트야 님…….","JPN":"逃げて……ください。アーディティヤ様……","ENG":"R... un, Miss Aditya...","TWN":"快……逃。阿迪亞……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"사람의 목숨은…… 소중하다면서요…….\xA0","JPN":"人の命は……大切だって言ってたじゃないですか……\xA0","ENG":"Life is important... remember...?\xA0","TWN":"性命……要緊……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……라비의 딸 아샤.","JPN":"……ラビの娘、アーシャ。","ENG":"...Ravi's daughter, Asha.","TWN":"……她是拉維的女兒，阿莎。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"다시는 나 때문에…… 소중한 이들을 잃지 않겠다.","JPN":"もう二度と、私のせいで……大切な人を失うものか。","ENG":"I will not lose those precious to me... through my own fault ever again.","TWN":"不會再因為我……而失去重要的人。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"난 아샤를 구해야 한다. 설령 내가 죽게 될지라도.","JPN":"私はアーシャを助けなければならない。たとえ自分が死ぬことになろうとも。","ENG":"I must save Asha. Even if it means my death.","TWN":"我要去救阿莎，即使我會死。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"결국 이번에도 혼자 남게 되겠네요.","JPN":"結局、今回もまた一人になりますね。","ENG":"Seems that you're all alone again.","TWN":"看來這次也只剩下自己一個。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"당연한 수순이지.","JPN":"当然なまでだ。","ENG":"A natural outcome.","TWN":"這是理所當然的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"이 자는 항상 고독할 수밖에 없는 운명이니까.","JPN":"彼女は一人になるしかない運命なんだから。","ENG":"This one is fated to always be alone.","TWN":"這個人註定會永遠孤獨。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"그렇네요. 지금도, 결국 홀로 남을 수밖에 없는 상황에 처해있군요.","JPN":"そうですね。今だって、結局は一人になろうとしています。","ENG":"Yes. Even now, the situation forces her to be alone.","TWN":"沒錯，甚至現在，也只能獨自一人。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRIEST_ORDER_NPC_NULL","text":{"KOREA":"이대로라면, 저 아이도 자기 손으로 죽이겠어요.","JPN":"このままでは、あの子まで殺めてしまいますね。","ENG":"At this rate, that child will die in her own hands.","TWN":"照這樣下去，那個孩子也會被她親手殺掉的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRIEST_ORDER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MAN_NPC_GEASS_QM","text":{"KOREA":"태양에 가까이 다가갈수록 몸이 타버리는 건 거스를 수 없으니까.\xA0","JPN":"太陽に近づけば、身体が燃え尽きてしまうのは避けられないことだ。\xA0","ENG":"For anyone who gets too close to the sun will eventually burn.\xA0","TWN":"越靠近太陽，身體被灼燒得就越厲害，這是無法避免的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MAN_NPC_GEASS_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"어차피 혼자 남을 운명이라면…… 적어도 나 때문에 동료들을 다치게 두진 않겠어.","JPN":"どうせ一人になる運命なら……せめて自分のせいで、仲間を傷つけさせはしない。","ENG":"If I am fated to be alone... then the least I can do is not let my comrades get hurt.","TWN":"如果註定要孤獨一人……至少不會讓同伴再因為我而受傷。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"……끝까지 우릴 받아들이지 못하겠다면, 알겠습니다.","JPN":"……最後まで私たちを受け入れることができないなら、わかりました。","ENG":"...If you refuse to accept us, then very well.","TWN":"……如果你到最後還是無法接受我們，那好吧。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"라비의 이름도, 당신과 함께할 자격도 모두 당신만 흡수하면 가능한 일이니까요.","JPN":"ラビの名も、あなたと共にする資格も、すべてあなたを吸収さえしてしまえば済むことですから。","ENG":"Ravi's name and your joining are both possible after absorbing you.","TWN":"只要吸收你，拉維的名字和與你在一起的資格都將成為可能。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"드디어 그 인간의 탈을 벗는 건가? 훨씬 어울리는군.","JPN":"ようやくその人間の殻を脱ぐのか？　そのほうがずっとお似合いだ。","ENG":"Have you finally chosen to take off that human disguise? You look much better now.","TWN":"終於要脫下你的人皮偽裝嗎？這才更適合你。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"덤벼라. 자기가 인간인줄 아는 미친 침식체.","JPN":"かかって来い。自分を人間だと思い込んでいる狂った侵食体め。","ENG":"Come at me. The insane C.O. that thinks it is human.","TWN":"來吧，你這個自以為是人的東西。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};